INSERT INTO `vtiger_crmentity` (`crmid`, `smcreatorid`, `smownerid`, `modifiedby`, `setype`, `description`, `createdtime`, `modifiedtime`, `viewedtime`, `status`, `version`, `presence`, `deleted`, `smviewer`) VALUES
(10, 1, 1, 1, 'Calendar', 'Para comenzar a organizar la gestiÃ³n de tus clientes es cargar la informaciÃ³n de:\r\n\r\nPersonas interesadas en tus productos y servicios (prospectos)\r\nPersonas con las que tienes un tipo de negociaciÃ³n (oportunidades de venta) y\r\n y clientes (cuentas) con informaciÃ³n de personas o clientes con las que ya has cerrado un negocio y te gustarÃ­a seguir vendiendo. \r\n\r\nComienza a probar...\r\n\r\nHaz clic en el sÃ­mbolo de Crear "+" y comienza a cargar informaciÃ³n. \r\n\r\n<img src="themes/images/task1.png"/>\r\n\r\n\r\nPara asignar responsables y ver la listas que ha cargado consulte:\r\n\r\nNegocio > Ventas ( y verÃ¡s todas sus oportunidades), \r\nNegocio > Marketing (y verÃ¡s todos sus prospectos)  \r\nEmpresa > AdministraciÃ³n (clientes)\r\n\r\nSi traes estos datos de venta desde un excel o de otro crm, puedes importarlos como un .cvs en la opciÃ³n importar.\r\n\r\n<img src="themes/images/task3.png"/>', '2016-04-11 16:57:10', '2016-04-11 16:57:10', NULL, NULL, 0, 1, 0, NULL),
(11, 1, 1, 1, 'Calendar', 'InformaciÃ³n de la empresa: aquÃ­ cargarÃ¡s toda la informaciÃ³n de tu negocio que tienes que proporcionar para los presupuestos y facturas. Nombre de la empresa, pÃ¡gina web, cÃ³digo postal, etc. \r\nMoneda: define en quÃ© moneda estÃ¡s definiendo el precio de los productos. Desde tu CRM-Facil podrÃ¡s manejar mÃºltiples monedas. \r\n\r\n3) ConfiguraciÃ³n de impuestos: define los impuestos de valor agregado y otras acciones impostivas que deberÃ¡s reflejar en tu facturaciÃ³n\r\n\r\n4) Productos y servicios: establece caracterÃ­sticas de productos o servicios, condiciones, precios y existencia. AsÃ­ tu equipo comercial estarÃ¡ preparado para vender. \r\n\r\n\r\nPuedes ver otras configuraciones aquÃ­.\r\n\r\nFormas de pago\r\nCorreo y contacto', '2016-04-11 16:57:10', '2016-04-11 16:57:10', NULL, NULL, 0, 1, 0, NULL),
(12, 1, 1, 1, 'Calendar', 'Para poner a funcionar tu CRM-FÃ¡cil es importante que invites a las personas que estÃ¡n trabajando en el Ã¡rea comercial de tu empresa o en la atenciÃ³n al cliente. \r\n\r\nPara hacerlo haz clic en crear y en la opciÃ³n Invitar Colaborador\r\n\r\n<img src="themes/images/task4.png" />\r\n\r\n\r\nAl invitar a tu equipo podrÃ¡s asignarles roles podrÃ¡s crear usuarios y claves de entrada, que automÃ¡ticamente se enviarÃ¡n a su correo\r\n\r\nNo olvides organizar el trabajo\r\n\r\nPara cada una de las acciones comerciales y de atenciÃ³n al cliente podrÃ¡s asignar un responsable (incluso tu mismo). \r\nPara hacerlo, visita en la opciÃ³n "Negocio" las listas de  prospectos, oportunidades de venta y atenciÃ³n al cliente y asigna responsables. \r\n\r\nPara consultar cÃ³mo avanza tu equipo, no olvides que puedes ver este TimeLine\r\n\r\nPara ver la lista de usuarios que habÃ©is creado, haz clic en en botÃ³n de configuraciÃ³n y haz clic en Usuarios. \r\n\r\n<img src="themes/images/task2.png" />', '2016-04-11 16:57:10', '2016-04-11 16:57:10', NULL, NULL, 0, 1, 0, NULL),
(13, 1, 1, 1, 'Calendar', 'Cuando cierres una venta, probablemente vendrÃ¡n otras acciones claves\r\n\r\nEnviar, cobrar y gestionar facturas\r\n\r\n2) Organizar tareas de atenciÃ³n al cliente:\r\n\r\nÂ¿En la opciÃ³n crear, puedes agregar una nueva tarea que un cliente te ha reportado por correo, en persona o por telefÃ³no. \r\n\r\n<img src="themes/images/task5.png" />\r\n\r\nAl hacer esto, automÃ¡ticamente aparecerÃ¡ en tu panel de pedidos de tu CRM-FÃ¡cil donde podrÃ¡s asignar responsables (incluso tu mismo) y prioridades. \r\n\r\n\r\n\r\n', '2016-04-11 16:57:10', '2016-04-11 16:57:10', NULL, NULL, 0, 1, 0, NULL),
