(4, 'Leads', '', 1, 'funnel', 'Embudo de Oportunidades', 'H58#H68', 'SELECT SUM(amount) as data, sales_stage as headers FROM vtiger_potential INNER JOIN vtiger_crmentity ON vtiger_potential.potentialid = vtiger_crmentity.crmid AND deleted = 0 INNER JOIN vtiger_sales_stage USING (sales_stage) WHERE sales_stage not like ''Closed%'' GROUP BY sales_stage ORDER BY sales_stage_id', NULL, 1, 0, 0, NULL),
(5, 'Leads', 'salutation', 1, 'barra', 'Origen de Potenciales Clientes', 'H58#H68', NULL, NULL, 0, 0, 1, NULL),
(6, 'Leads', '', 1, 'funnel', 'Embudo de Prospectos', 'H58#H68', 'SELECT count(*) as data, leadstatus as headers FROM vtiger_leaddetails INNER JOIN vtiger_crmentity ON vtiger_leaddetails.leadid = vtiger_crmentity.crmid AND deleted = 0 INNER JOIN vtiger_leadstatus USING (leadstatus) WHERE 1 GROUP BY leadstatus ORDER BY leadstatusid', NULL, 1, 0, 1, NULL);
