INSERT INTO `vtiger_kpisboxscore` (`kpisboxscoreid`, `name`, `description`, `module`, `querykpi`, `querykpisemanal`, `active`) VALUES
(1, 'Cantidad de Clientes por Mes MA', 'Esto es una prueba de KPI para Boxscore MA', 'Accounts', 'SELECT count(*) as valorkpi,month(proximo_vencimiento) as mes,year(proximo_vencimiento) as anio FROM `vtiger_account` a join vtiger_crmentity crm on (crm.crmid = a.accountid) where crm.deleted = 0 and proximo_vencimiento is not null and year(proximo_vencimiento) = {{ANIO}} and month(proximo_vencimiento) = {{MES}}\n', 'SELECT count(*) as valorkpi,month(proximo_vencimiento) as mes,year(proximo_vencimiento) as anio, week(proximo_vencimiento) as semana  FROM `vtiger_account` a join vtiger_crmentity crm on (crm.crmid = a.accountid) where crm.deleted = 0 and proximo_vencimiento is not null and year(proximo_vencimiento) = {{ANIO}} and month(proximo_vencimiento) = {{MES}}  and week(proximo_vencimiento) = {{SEMANA}}\n', 1),
(3, 'Cantidad de Contactos por Mes', 'Esto es una prueba de KPI para Boxscore - Contactos', 'Contacts', 'SELECT count(*) as valorkpi,month(proximo_vencimiento) as mes,year(proximo_vencimiento) as anio FROM `vtiger_account` a join vtiger_crmentity crm on (crm.crmid = a.accountid) where crm.deleted = 0 and proximo_vencimiento is not null and year(proximo_vencimiento) = {{ANIO}} and month(proximo_vencimiento) = {{MES}}\n', 'SELECT count(*) as valorkpi,month(proximo_vencimiento) as mes,year(proximo_vencimiento) as anio, week(proximo_vencimiento) as semana  FROM `vtiger_account` a join vtiger_crmentity crm on (crm.crmid = a.accountid) where crm.deleted = 0 and proximo_vencimiento is not null and year(proximo_vencimiento) = {{ANIO}} and month(proximo_vencimiento) = {{MES}}  and week(proximo_vencimiento) = {{SEMANA}}\n', 1);
