(27, 3, 'Comercial', 'wGraph', 'bar2', '', 23, 4, 'SELECT DATE_FORMAT(invoicedate,''%m-%Y'') as headers, sum(total) as data from vtiger_crmentity INNER JOIN vtiger_invoice\nON (crmid = invoiceid AND deleted = 0)\nGROUP BY DATE_FORMAT(invoicedate,''%m-%Y'')'),
(28, 3, 'Tareas', 'TodoTask', '', '', 13, 1, NULL),
(30, 3, 'Leads creados por día', 'wGraph', 'bar', '', 13, 6, 'SELECT headers, data FROM \n(SELECT DATE_FORMAT(createdtime,''%d-%m-%Y'') as headers, count(*) as data from vtiger_crmentity WHERE setype = ''Leads'' AND deleted = 0\nGROUP BY DATE_FORMAT(createdtime,''%d-%m-%Y'') ORDER BY 1 DESC LIMIT 0,10) as T1 ORDER BY 1 ASC'),
(33, 3, 'Cantidad de prospectos por fuente', 'wGraph', 'donut', '', 7, 7, 'SELECT leadsource as headers, count(*) as data from vtiger_crmentity INNER JOIN vtiger_leaddetails ON (crmid = leadid AND deleted = 0)\r\nWHERE 1 GROUP BY leadsource'),
(40, 143, 'Oportunidades', 'Widget', '', '', 2, 9, NULL),
(42, 143, 'Oportunidades', 'Widget', '', '', 2, 10, NULL),
(45, 143, 'Oportunidades', 'Widget', '', '', 2, 11, NULL),
(51, 143, 'Prospectos', 'Widget', '', '', 7, 12, NULL),
(54, 147, 'Clientes por importancia', 'wGraph', 'bar', '', 6, 1, NULL),
(56, 143, 'Prospectos ultima semana', 'wGraph', 'bar', '', 7, 13, NULL),
(61, 147, 'Cuentas por Estado', 'wGraph', 'pie', '', 6, 2, NULL),
(63, 3, 'Marketing', 'wTitle', NULL, '¿Cómo va la captación de prospectos?', 29, 5, NULL),
(64, 3, 'Comercial', 'wTitle', NULL, '¿Cómo van las ventas de tu empresa?', 29, 3, NULL),
(65, 3, 'Embudo de Oportunidades', 'wGraph', 'funnel', '', 7, 7, 'SELECT SUM(amount) as data, sales_stage as headers FROM vtiger_potential\n						INNER JOIN vtiger_crmentity ON vtiger_potential.potentialid = vtiger_crmentity.crmid\n						AND deleted = 0 \nINNER JOIN vtiger_sales_stage USING (sales_stage) WHERE sales_stage not like ''Closed%'' GROUP BY sales_stage ORDER BY sales_stage_id'),
(66, 3, 'Embudo de Prospectos', 'wGraph', 'funnel', '', 7, 7, 'SELECT count(*) as data, leadstatus as headers FROM vtiger_leaddetails\r\n						INNER JOIN vtiger_crmentity ON vtiger_leaddetails.leadid = vtiger_crmentity.crmid\r\n						AND deleted = 0 \r\nINNER JOIN vtiger_leadstatus USING (leadstatus) WHERE 1 GROUP BY leadstatus ORDER BY leadstatusid');
