INSERT INTO `vtiger_panel_graph_widgets` (`widgetid`, `panelid`, `waid`, `widget`, `order`) VALUES
(12, 24, 3, '							<div class="col-lg-6">\n								<div class="main-box">	\n								<header class="main-box-header clearfix">\n									<h2>Indicadores Clave</h2>\n									</header>\n									<div class="main-box-body clearfix">\n										<div class="clearfix">\n											<div class="infographic-box merged merged-top pull-left">\n												<i class="fa fa-shopping-cart purple-bg" style="margin-right:10px;margin-top:5px"></i>\n												<span class="value purple">$NEW_LEADS$</span>\n												<span class="headline">Nuevos Prospectos</span>\n											</div>\n											<div class="infographic-box merged merged-top merged-right pull-left">\n												<i class="fa fa-money green-bg"  style="margin-right:10px;margin-top:5px"></i>\n												<span class="value green">&euro; $POTENTIALS_AMOUNT$</span>\n												<span class="headline">Oportunidades de venta</span>\n											</div>\n										</div>\n										<div class="clearfix">\n											<div class="infographic-box merged pull-left">\n												<i class="fa fa-eye yellow-bg"  style="margin-right:10px;margin-top:5px"></i>\n												<span class="value yellow">$NEW_TASKS$</span>\n												<span class="headline">Tareas nuevas y sin asignar</span>\n											</div>\n											<div class="infographic-box merged merged-right pull-left">\n												<i class="fa fa-star-half-o red-bg"  style="margin-right:10px;margin-top:5px"></i>\n												<span class="value red">$INVOICE_PENDING$</span>\n												<span class="headline">Facturas por cobrar</span>\n											</div>\n										</div>\n									</div>\n								</div>\n							</div>', 2),
(15, 27, 3, '<div class="col-lg-12">\n\n									<div class="main-box">\n										<header class="main-box-header clearfix">\n											<h2>Embudo de ventas</h2>\n										</header>\n										\n										<div class="main-box-body clearfix">\n											<div id="graph-flot-bar-horizontal" style="height: 435px; padding: 0px; position: relative;"><canvas class="flot-base" width="501" height="435" style="direction: ltr; position: absolute; left: 0px; top: 0px; width: 501px; height: 435px;"></canvas><div class="flot-text" style="position: absolute; top: 0px; left: 0px; bottom: 0px; right: 0px; font-size: smaller; color: rgb(84, 84, 84);"><div class="flot-x-axis flot-x1-axis xAxis x1Axis" style="position: absolute; top: 0px; left: 0px; bottom: 0px; right: 0px; display: block;"><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 22px; text-align: center;">0</div><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 112px; text-align: center;">5</div><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 199px; text-align: center;">10</div><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 289px; text-align: center;">15</div><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 379px; text-align: center;">20</div><div class="flot-tick-label tickLabel" style="position: absolute; max-width: 71px; top: 418px; left: 469px; text-align: center;">25</div></div><div class="flot-y-axis flot-y1-axis yAxis y1Axis" style="position: absolute; top: 0px; left: 0px; bottom: 0px; right: 0px; display: block;"><div class="flot-tick-label tickLabel" style="position: absolute; top: 405px; left: 0px; text-align: right;">-1.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 337px; left: 4px; text-align: right;">0.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 270px; left: 4px; text-align: right;">1.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 203px; left: 4px; text-align: right;">2.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 135px; left: 4px; text-align: right;">3.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 68px; left: 4px; text-align: right;">4.0</div><div class="flot-tick-label tickLabel" style="position: absolute; top: 1px; left: 4px; text-align: right;">5.0</div></div></div><canvas class="flot-overlay" width="501" height="435" style="direction: ltr; position: absolute; left: 0px; top: 0px; width: 501px; height: 435px;"></canvas></div>\n										</div>\n									</div>\n								</div>\n								\n								<!-- this page specific inline scripts -->\n	<script>\n	jQuery(function() {\n		\n		\n		\n		// bar chart - horizontal\n		if (jQuery(''#graph-flot-bar-horizontal'').length) {\n			var db1 = [];\n			for (var i = 0; i <= 4; i += 1) {\n				db1.push([parseInt(Math.random() * 30), i]);\n			}\n\n			var db2 = [];\n			for (var i = 0; i <= 4; i += 1) {\n				db2.push([parseInt(Math.random() * 30), i]);\n			}\n\n			var db3 = [];\n			for (var i = 0; i <= 4; i += 1) {\n				db3.push([parseInt(Math.random() * 30), i]);\n			}\n			\n			var series = new Array();\n\n			series.push({\n				data : db1,\n				bars : {\n					show : true,\n					barWidth : 0.2,\n					order : 1,\n					lineWidth: 1,\n					horizontal: true,\n					fill: 1\n				}\n			});\n			series.push({\n				data : db2,\n				bars : {\n					show : true,\n					barWidth : 0.2,\n					order : 2,\n					lineWidth: 1,\n					horizontal: true,\n					fill: 1\n				}\n			});\n			series.push({\n				data : db3,\n				bars : {\n					show : true,\n					barWidth : 0.2,\n					order : 3,\n					lineWidth: 1,\n					horizontal: true,\n					fill: 1\n				}\n			}); \n\n			jQuery.plot("#graph-flot-bar-horizontal", series, {\n				colors: [''#e74c3c'', ''#f1c40f'', ''#2ecc71'', ''#3498db'', ''#9b59b6'', ''#95a5a6''],\n				grid: {\n					tickColor: "#ddd",\n					borderWidth: 0\n				},\n				shadowSize: 0\n			});\n		}\n		\n	});\n	\n	function labelFormatter(label, series) {\n		return "<div style=''font-size:8pt; text-align:center; padding:2px; color:white;''>" + label + "<br/>" + Math.round(series.percent) + "%</div>";\n	}\n	</script>\n	\n', 3),
(16, 28, 2, '\r\n						<div class="col-md-4 col-sm-6 col-xs-12">\r\n							<div class="main-box small-graph-box emerald-bg" id="waid2">\r\n								<span class="value" id="waid2-val">[$W_VAL]</span>\r\n								<span class="headline" id="waid2-lbl">Tareas</span>\r\n								<div class="progress">\r\n									<div style="width: [$W_VAL]%;" aria-valuemax="100" aria-valuemin="0" aria-valuenow="[$W_VAL]" role="progressbar" class="progress-bar">\r\n										<span class="sr-only">[$W_VAL]% Completo</span>\r\n									</div>\r\n								</div>\r\n								<span class="subinfo">\r\n									<i class="fa fa-download emerald-bg" id="waid2-ico"></i> <span id="waid2-lbl2">Nuevas y sin asignar</span>\r\n								</span>\r\n							</div>\r\n						</div>\r\n					', 1),
(18, 30, 6, '', 4),
(21, 33, 6, '', 5),
